CREATE TABLE recruiting_cycles (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), name text NOT NULL, entry_term text NOT NULL UNIQUE, is_active boolean NOT NULL DEFAULT true, archived_at timestamptz, created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE prospects (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), full_name text NOT NULL, normalized_name text NOT NULL, preferred_name text, school_id uuid REFERENCES schools(id) ON DELETE SET NULL, recruiting_cycle_id uuid NOT NULL REFERENCES recruiting_cycles(id) ON DELETE RESTRICT, source text NOT NULL, stage text NOT NULL, interest_level text NOT NULL DEFAULT 'cool', graduation_year integer, is_transfer boolean NOT NULL DEFAULT false, closed_outcome text, archived_at timestamptz, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now()); CREATE INDEX prospects_cycle_stage_index ON prospects(recruiting_cycle_id, stage); CREATE INDEX prospects_name_index ON prospects(normalized_name);
CREATE TABLE prospect_contacts (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), prospect_id uuid NOT NULL REFERENCES prospects(id) ON DELETE CASCADE, type text NOT NULL, value text NOT NULL, is_primary boolean NOT NULL DEFAULT false, provenance text, created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE prospect_stage_history (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), prospect_id uuid NOT NULL REFERENCES prospects(id) ON DELETE CASCADE, stage text NOT NULL, note text, changed_by_user_id uuid REFERENCES users(id) ON DELETE SET NULL, created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE prospect_interest_history (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), prospect_id uuid NOT NULL REFERENCES prospects(id) ON DELETE CASCADE, interest_level text NOT NULL, note text, changed_by_user_id uuid REFERENCES users(id) ON DELETE SET NULL, created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE prospect_score_snapshots (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), prospect_id uuid NOT NULL REFERENCES prospects(id) ON DELETE CASCADE, total_score integer NOT NULL, missing_data jsonb NOT NULL DEFAULT '[]'::jsonb, override_note text, calculated_at timestamptz NOT NULL DEFAULT now()); CREATE TABLE prospect_score_factors (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), snapshot_id uuid NOT NULL REFERENCES prospect_score_snapshots(id) ON DELETE CASCADE, factor text NOT NULL, contribution integer NOT NULL, rationale text NOT NULL);
CREATE TABLE duplicate_candidates (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), prospect_id uuid NOT NULL REFERENCES prospects(id) ON DELETE CASCADE, candidate_prospect_id uuid NOT NULL REFERENCES prospects(id) ON DELETE CASCADE, reason text NOT NULL, status text NOT NULL DEFAULT 'pending', created_at timestamptz NOT NULL DEFAULT now(), UNIQUE(prospect_id, candidate_prospect_id)); CREATE TABLE duplicate_reviews (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), candidate_id uuid NOT NULL REFERENCES duplicate_candidates(id) ON DELETE CASCADE, reviewer_user_id uuid NOT NULL REFERENCES users(id) ON DELETE RESTRICT, decision text NOT NULL, note text, created_at timestamptz NOT NULL DEFAULT now());
